"use client";
import React, { useState } from "react";

export default function AddItemPage() {
  const [menuId, setMenuId] = useState(""); // populate with actual menus
  const [category, setCategory] = useState("");
  const [name, setName] = useState("");
  const [desc, setDesc] = useState("");
  const [price, setPrice] = useState("");

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    console.log({ menuId, category, name, desc, price });
    // TODO: Call backend API to save item
  };

  return (
    <div className="min-h-screen bg-black text-white flex flex-col items-center justify-center px-6">
      <h2 className="text-3xl font-oswald uppercase tracking-wide text-yellow-500 mb-6">
        Add Menu Item
      </h2>

      <form
        onSubmit={handleSubmit}
        className="w-full max-w-md bg-gray-900 p-6 rounded-lg shadow-lg border border-yellow-600"
      >
        {/* Menu Dropdown */}
        <div className="mb-4">
          <label className="block mb-2 text-sm font-semibold">Select Menu</label>
          <select
            value={menuId}
            onChange={(e) => setMenuId(e.target.value)}
            className="w-full px-3 py-2 bg-black border border-yellow-600 rounded text-white"
          >
            <option value="">-- Choose Menu --</option>
            <option value="1">Drinks</option>
            <option value="2">Food</option>
          </select>
        </div>

        {/* Category */}
        <div className="mb-4">
          <label className="block mb-2 text-sm font-semibold">Category</label>
          <input
            type="text"
            value={category}
            onChange={(e) => setCategory(e.target.value)}
            className="w-full px-3 py-2 bg-black border border-yellow-600 rounded text-white focus:outline-none"
            placeholder="e.g. Appetizers"
          />
        </div>

        {/* Item Name */}
        <div className="mb-4">
          <label className="block mb-2 text-sm font-semibold">Item Name</label>
          <input
            type="text"
            value={name}
            onChange={(e) => setName(e.target.value)}
            className="w-full px-3 py-2 bg-black border border-yellow-600 rounded text-white focus:outline-none"
            placeholder="e.g. Lamb Chops"
          />
        </div>

        {/* Description */}
        <div className="mb-4">
          <label className="block mb-2 text-sm font-semibold">Description</label>
          <textarea
            value={desc}
            onChange={(e) => setDesc(e.target.value)}
            className="w-full px-3 py-2 bg-black border border-yellow-600 rounded text-white focus:outline-none"
            placeholder="Grilled lamb chops topped with sauce"
          />
        </div>

        {/* Price */}
        <div className="mb-4">
          <label className="block mb-2 text-sm font-semibold">Price</label>
          <input
            type="number"
            value={price}
            onChange={(e) => setPrice(e.target.value)}
            className="w-full px-3 py-2 bg-black border border-yellow-600 rounded text-white focus:outline-none"
            placeholder="26"
          />
        </div>

        <button
          type="submit"
          className="w-full py-2 bg-yellow-500 text-black font-bold rounded hover:bg-yellow-400"
        >
          Save Item
        </button>
      </form>
    </div>
  );
}
